static uint32_t crc32_table[256];
static int crc32_table_computed = 0;

static void make_crc32_table(void) {
    uint32_t c;
    int n, k;
    for (n = 0; n < 256; n++) {
        c = (uint32_t)n;
        for (k = 0; k < 8; k++) {
            if (c & 1)
                c = 0xedb88320 ^ (c >> 1);
            else
                c = c >> 1;
        }
        crc32_table[n] = c;
    }
    crc32_table_computed = 1;
}

static uint32_t crc32(const unsigned char *buf, size_t len) {
    uint32_t c = 0xffffffff;
    size_t i;
    if (!crc32_table_computed) make_crc32_table();
    for (i = 0; i < len; i++)
        c = crc32_table[(c ^ buf[i]) & 0xff] ^ (c >> 8);
    return c ^ 0xffffffff;
}

static void write_chunk(FILE *f, const char *type, const unsigned char *data, uint32_t len) {
    unsigned char len_buf[4];
    unsigned char crc_buf[4];
    uint32_t crc_val;
    unsigned char type_buf[4];
    size_t i;

    /* length big-endian */
    len_buf[0] = (len >> 24) & 0xff;
    len_buf[1] = (len >> 16) & 0xff;
    len_buf[2] = (len >> 8) & 0xff;
    len_buf[3] = len & 0xff;
    fwrite(len_buf, 1, 4, f);

    /* chunk type */
    type_buf[0] = type[0];
    type_buf[1] = type[1];
    type_buf[2] = type[2];
    type_buf[3] = type[3];
    fwrite(type_buf, 1, 4, f);

    /* data */
    if (len > 0 && data != NULL) {
        fwrite(data, 1, len, f);
    }

    /* CRC over type + data */
    {
        unsigned char *crc_input = malloc(4 + len);
        if (!crc_input) { fprintf(stderr, "malloc failed\n"); exit(1); }
        memcpy(crc_input, type_buf, 4);
        if (len > 0 && data != NULL) {
            memcpy(crc_input + 4, data, len);
        }
        crc_val = crc32(crc_input, 4 + len);
        free(crc_input);
    }
    crc_buf[0] = (crc_val >> 24) & 0xff;
    crc_buf[1] = (crc_val >> 16) & 0xff;
    crc_buf[2] = (crc_val >> 8) & 0xff;
    crc_buf[3] = crc_val & 0xff;
    fwrite(crc_buf, 1, 4, f);
