        unsigned char mhdr[28];
        memset(mhdr, 0, 28);
        /* width = 1 */
        mhdr[0] = 0; mhdr[1] = 0; mhdr[2] = 0; mhdr[3] = 1;
        /* height = 1 */
        mhdr[4] = 0; mhdr[5] = 0; mhdr[6] = 0; mhdr[7] = 1;
        /* ticks = 1 */
        mhdr[8] = 0; mhdr[9] = 0; mhdr[10] = 0; mhdr[11] = 1;
        /* layer count = 1 */
        mhdr[12] = 0; mhdr[13] = 0; mhdr[14] = 0; mhdr[15] = 1;
        /* bitdepth = 8 */
        mhdr[20] = 8;
        /* colortype = 3 (indexed-color) */
        mhdr[24] = 3;
        /* simplicity = 7 (bit 0: simple frame, bit 1: transparency, bit 2: JNG) */
        mhdr[25] = 0; mhdr[26] = 0; mhdr[27] = 7;
